mapper.update:
UPDATE uv_oil_matte_compatibility SET
    product_id = #{productId},
    post_processing_step = #{postProcessingStep},
    compatibility_status = #{compatibilityStatus},
    display_order = #{displayOrder}
WHERE id = #{id}

mapper.select:
SELECT p.id FROM uv_oil_matte_product p INNER JOIN uv_oil_matte_compatibility c ON p.id = c.product_id
AND (p.material_name LIKE CONCAT('%', #{keyword}, '%') OR p.material_code LIKE CONCAT('%', #{keyword}, '%') OR p.stock_code LIKE CONCAT('%', #{keyword}, '%') OR p.notes LIKE CONCAT('%', #{keyword}, '%'))
AND c.post_processing_step IN
#{step}
GROUP BY p.id HAVING COUNT(DISTINCT c.post_processing_step) = #{stepCount} ORDER BY MAX(p.material_code) ASC, p.id ASC LIMIT #{limit} OFFSET #{offset}

SELECT * FROM uv_oil_matte_product WHERE id IN
#{id}
ORDER BY material_code ASC, id ASC

SELECT product_id, post_processing_step, compatibility_status FROM uv_oil_matte_compatibility WHERE product_id IN
#{id}
AND post_processing_step IN
#{step}
ORDER BY product_id, post_processing_step
